const NL = String.fromCharCode(10);

// ── Credentials (hardcoded — workflow static data was not set) ────────────
const N8N_KEY       = 'REDACTED_JWT_TOKEN';
const BROAD_SCANNER_ID = '975pZZEtxeUbzI22';
const ALPACA_KEY    = 'REDACTED_ALPACA_KEY_ID';
const ALPACA_SECRET = 'REDACTED_ALPACA_SECRET';

// ── Dates ─────────────────────────────────────────────────────────────────
const today     = new Date();
const dateStr   = today.toLocaleDateString('en-US', {
  timeZone: 'America/New_York', month: 'long', day: 'numeric', year: 'numeric'
});
const todayISO    = today.toISOString().substring(0, 10);
const yesterday   = new Date(today.getTime() - 86400000).toISOString().substring(0, 10);
const afterTS     = yesterday + 'T00:00:00Z';

// ── 1. Fetch yesterday Broad Scanner executions (no status filter — filter in code) ──
let successRuns = 0, errorRuns = 0;
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url:  'https://tradenextgen.app.n8n.cloud/api/v1/executions',
    qs:   { workflowId: BROAD_SCANNER_ID, limit: 200 },
    headers: { 'X-N8N-API-KEY': N8N_KEY },
    json: true,
  });
  for (const e of (resp.data || [])) {
    const d = (e.startedAt || '').substring(0, 10);
    if (d !== yesterday) continue;
    if (e.status === 'success') successRuns++;
    else if (e.status === 'error') errorRuns++;
  }
} catch (e) {
  console.log('[BUILD REPORT] n8n API error:', e.message);
}

// ── 2. Fetch Alpaca snapshots for pre-market movers ───────────────────────
const tickers = ['TSLA','NVDA','AMD','GILD','MSFT','SPY','QQQ','NBIS','CRWV',
                 'META','AAPL','GOOGL','PLTR','AVGO','ARM','SMCI','APP','AMZN','NFLX','UBER'];
let movers = [], totalSignals = 0, buyCount = 0, sellCount = 0;

try {
  const snaps = await this.helpers.httpRequest({
    method: 'GET',
    url:  'https://data.alpaca.markets/v2/stocks/snapshots',
    qs:   { symbols: tickers.join(','), feed: 'sip' },
    headers: { 'APCA-API-KEY-ID': ALPACA_KEY, 'APCA-API-SECRET-KEY': ALPACA_SECRET },
    json: true,
  });
  for (const [ticker, snap] of Object.entries(snaps || {})) {
    if (!snap || !snap.latestTrade || !snap.prevDailyBar) continue;
    const changePct = (snap.latestTrade.p - snap.prevDailyBar.c) / snap.prevDailyBar.c * 100;
    movers.push({ ticker, changePct });
    if (Math.abs(changePct) >= 0.7) {
      totalSignals++;
      changePct < 0 ? sellCount++ : buyCount++;
    }
  }
  movers.sort((a, b) => Math.abs(b.changePct) - Math.abs(a.changePct));
} catch (e) {
  console.log('[BUILD REPORT] Alpaca snapshot error:', e.message);
}

const top3 = movers.slice(0, 3)
  .map(m => m.ticker + ' ' + (m.changePct >= 0 ? '+' : '') + m.changePct.toFixed(1) + '%')
  .join(', ');

// ── 3. Build message ──────────────────────────────────────────────────────
const healthy    = successRuns > 0;
const statusIcon = healthy ? String.fromCharCode(9989) : String.fromCharCode(9888);
const statusText = healthy ? 'Healthy ' + statusIcon : 'Issues detected ' + statusIcon;

const lines = [
  String.fromCharCode(128202) + ' <b>QUANTUM DAILY SUMMARY</b> ' + String.fromCharCode(8212) + ' ' + dateStr,
  '',
  '<b>Scanned:</b> 103 tickers',
  '<b>Signals generated:</b> ' + totalSignals + ' (' + sellCount + ' SELL, ' + buyCount + ' BUY)',
  '<b>Top movers:</b> ' + (top3 || 'Market not open yet'),
  '',
  '<b>Status:</b> ' + statusText,
  'Broad Scanner ran ' + successRuns + ' times yesterday (' + errorRuns + ' errors)',
];

return [{ json: { message: lines.join(NL) } }];
